import{c as r,Q as o,j as a,m as e}from"./chunks/framework.DpF7k2f3.js";const d=JSON.parse('{"title":"제8장 프롬프트 엔지니어링에서 에이전트 개발로","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ko/part3-practice/chapter8.md","filePath":"ko/part3-practice/chapter8.md","lastUpdated":1779671667000}'),p={name:"ko/part3-practice/chapter8.md"};function n(s,t,i,c,l,_){return o(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="제8장-프롬프트-엔지니어링에서-에이전트-개발로" tabindex="-1">제8장 프롬프트 엔지니어링에서 에이전트 개발로 <a class="header-anchor" href="#제8장-프롬프트-엔지니어링에서-에이전트-개발로" aria-label="Permalink to &quot;제8장 프롬프트 엔지니어링에서 에이전트 개발로&quot;">​</a></h1><p>##本章에서 배울 것들</p><p>정식 내용에 들어가기 전에, 먼저 질문하겠습니다: 2023년 3월에 입사한 AI 개발자였다고 가정해 보십시오. 그때 가장 인기 있었던 것은 무엇이었습니까? 프롬프트 엔지니어였습니다 -听起来很酷하지만 실제로는 &quot;프롬프트 작성 방법&quot;만 아는 직책이었습니다. 당시의 AI 앱 개발은 말할 것도 없이 간단했습니다: 프롬프트를 하나 쓰면 AI가 답을 돌려주면 끝.</p><p>하지만 지금(2026년)도 &quot;프롬프트 작성&quot;이라는 방법만으로 먹고 살 수 있다면, 모래海滩에서 굶어 죽을 것입니다.</p><p>이 챕터의 핵심 과제는 당신이 <strong>全局적 시각을 구축</strong>하도록 돕는 것입니다. 명확히 보게 될 것들:</p><ol><li><strong>왜 프롬프트 엔지니어링이 출발점일 뿐인지</strong>: 무엇을 할 수 있는지, 천장이 어디인지</li><li><strong>Chain이 어떻게 이 천장을 해결하는지</strong>: 가장早い 엔지니어링 실전이 어떤 모양이었는지</li><li><strong>에이전트가 왜 필수적 진화인지</strong>: &quot;내가 너에게 뭘 할지 말해준다&quot;에서 &quot;네가 스스로 뭘 할지 결정해라&quot;로</li><li><strong>에이전트 비서가 의미하는 것</strong>: 기억, 성격, 장기 목표를 추가한 후의 질적 변화</li><li><strong>지금 당신이 어디에 서야 하는지</strong>: 2026년 생태계 지도와 선택 결정</li></ol><p><strong>선행 지식</strong>: 제5장 프롬프트 엔지니어링 기초, 제7장 AI 에이전트 핵심 로직.</p><hr><blockquote><p><strong>전체 번역은 곧 제공될 예정입니다. 지금은中文版을 읽으실 수 있습니다.</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part3-practice/chapter8.html">中文版阅读</a></p></blockquote>',9)])])}const g=r(p,[["render",n]]);export{d as __pageData,g as default};
